import { useState } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const fmtMs = (v) => v == null ? "\u2014" : `${v}ms`;

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── stacked bar for bot latency ─────────────────────── */
function StackedBar({ name, network, api, exchange, maxTotal }) {
  const total = network + api + exchange;
  const scale = (v) => `${(v / maxTotal) * 100}%`;
  return (
    <div style={{ marginBottom: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
        <span style={{ fontWeight: 600 }}>{name}</span>
        <span className="v2-mono">{total}ms</span>
      </div>
      <div style={{ display: "flex", height: 20, borderRadius: 6, overflow: "hidden", background: "rgba(255,255,255,0.04)" }}>
        <div style={{ width: scale(network), background: "var(--v2-blue)", transition: "width 0.25s" }} title={`Network: ${network}ms`} />
        <div style={{ width: scale(api), background: "var(--v2-amber)", transition: "width 0.25s" }} title={`API: ${api}ms`} />
        <div style={{ width: scale(exchange), background: "var(--v2-green)", transition: "width 0.25s" }} title={`Exchange: ${exchange}ms`} />
      </div>
    </div>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function Latency() {
  const { state } = useAppStore();
  const [sortCol, setSortCol] = useState("avg");

  /* poll dedicated v2 latency endpoint */
  const { data: latencyData, loading } = usePoll(
    async () => { const r = await http.get("/v2/latency"); return r.data; },
    { intervalMs: 10000, immediate: true, enabled: !state.offlineMode }
  );

  /* poll system health for status context */
  const { data: healthData } = usePoll(
    async () => { const r = await http.get("/system/health"); return r.data; },
    { intervalMs: 30000, immediate: true, enabled: !state.offlineMode }
  );

  /* poll bot telemetry for per-bot latency */
  const { data: telData } = usePoll(
    async () => { const r = await http.get("/telemetry/latest"); return r.data; },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Latency Breakdown</h1>
            <div className="v2-muted">Loading latency data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  /* Derive metrics from v2/latency response */
  const summary = latencyData?.summary ?? null;
  const histogram = latencyData?.histogram ?? [];
  const lastUpdated = latencyData?.last_updated ?? null;

  /* Derive bot latency from telemetry (exclude paper/marketing bots) */
  const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
  const botEntries = telData?.bots ?? {};
  const botLatencyList = Object.entries(botEntries).filter(([n]) => !PAPER_BOTS.has(n.toLowerCase())).map(([name, info]) => ({
    name: name.toUpperCase(),
    status: info.status ?? "UNKNOWN",
    lastHb: info.last_heartbeat ?? null,
    latency: info.payload?.latency_ms ?? null,
  }));

  /* System info */
  const apiStatus = healthData?.api ?? healthData?.status ?? null;

  return (
    <>
      {/* header */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Latency Breakdown</h1>
          <div className="v2-muted">Network, API, and exchange latency analysis across all endpoints.</div>
        </div>
        {lastUpdated && (
          <div className="v2-row">
            <span className="v2-pill v2-mono" style={{ fontSize: 10 }}>Updated: {new Date(lastUpdated).toLocaleTimeString()}</span>
          </div>
        )}
      </div>

      {/* top stats from /v2/latency summary */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="P50 Latency" value={summary ? fmtMs(summary.p50_ms) : "\u2014"} t={summary && summary.p50_ms < 50 ? "green" : "amber"} sub="Median response time" />
        <Stat label="P95 Latency" value={summary ? fmtMs(summary.p95_ms) : "\u2014"} t={summary && summary.p95_ms < 200 ? "green" : summary && summary.p95_ms < 500 ? "amber" : "red"} sub="95th percentile" />
        <Stat label="P99 Latency" value={summary ? fmtMs(summary.p99_ms) : "\u2014"} t={summary && summary.p99_ms < 500 ? "green" : "red"} sub="99th percentile" />
        <Stat label="Avg Latency" value={summary ? fmtMs(summary.avg_ms) : "\u2014"} t={summary && summary.avg_ms < 100 ? "green" : "amber"} sub={summary ? `${summary.samples?.toLocaleString() ?? "--"} samples` : "Waiting for data"} />
      </div>

      {/* Latency Histogram from /v2/latency */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Latency Distribution</div>
          {histogram.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Histogram Data" message="Latency histogram will appear when the API reports timing buckets." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {histogram.map((b, i) => {
                const maxCount = Math.max(...histogram.map(x => x.count), 1);
                const pct = (b.count / maxCount) * 100;
                return (
                  <div key={i} style={{ marginBottom: 8 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
                      <span>{b.bucket ?? b.label ?? `Bucket ${i + 1}`}</span>
                      <span className="v2-mono">{b.count.toLocaleString()}</span>
                    </div>
                    <div style={{ height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{
                        height: "100%", width: `${pct}%`, borderRadius: 6, transition: "width 0.4s ease",
                        background: i < 2 ? "var(--v2-green)" : i < 3 ? "var(--v2-amber)" : "var(--v2-red)",
                      }} />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Bot latency breakdown from /telemetry/latest */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Latency by Bot</div>
          {botLatencyList.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Bot Latency Data" message="Per-bot latency breakdown will appear when bots report timing telemetry." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {botLatencyList.map(b => {
                const statusColor = b.status === "OK" ? "green" : b.status === "ERR" ? "red" : "amber";
                return (
                  <div key={b.name} style={{ marginBottom: 16 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, marginBottom: 4 }}>
                      <span style={{ fontWeight: 600 }}>{b.name}</span>
                      <span className="v2-row" style={{ gap: 8 }}>
                        <span className={`v2-${statusColor}`} style={{ fontSize: 10, fontWeight: 600 }}>{b.status}</span>
                        {b.latency != null && <span className="v2-mono">{fmtMs(b.latency)}</span>}
                      </span>
                    </div>
                    {b.lastHb && (
                      <div className="v2-muted" style={{ fontSize: 10 }}>Last heartbeat: {new Date(b.lastHb).toLocaleString()}</div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* SLA compliance */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div className="v2-ct">SLA Compliance</div>
          {!summary ? (
            <V2EmptyState icon="\u29C6" title="No SLA Data" message="SLA compliance metrics will appear when the API tracks request thresholds." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "200px 120px 120px 100px" }}>
                <span>SLA Threshold</span>
                <span>Target</span>
                <span>Actual</span>
                <span>Status</span>
              </div>
              {[
                { name: "P50 < 50ms", target: "50ms", actual: summary.p50_ms, pass: summary.p50_ms < 50 },
                { name: "P95 < 200ms", target: "200ms", actual: summary.p95_ms, pass: summary.p95_ms < 200 },
                { name: "P99 < 500ms", target: "500ms", actual: summary.p99_ms, pass: summary.p99_ms < 500 },
                { name: "Avg < 100ms", target: "100ms", actual: summary.avg_ms, pass: summary.avg_ms < 100 },
              ].map(sla => (
                <div key={sla.name} className="v2-tr" style={{ gridTemplateColumns: "200px 120px 120px 100px" }}>
                  <span>{sla.name}</span>
                  <span className="v2-mono v2-muted">{sla.target}</span>
                  <span className="v2-mono">{fmtMs(sla.actual)}</span>
                  <span className={`v2-${sla.pass ? "green" : "red"}`} style={{ fontWeight: 600 }}>{sla.pass ? "PASS" : "FAIL"}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
